// n8nの入力データを取得（HTTP Requestノードの結果）
const items = $input.all();

// 日付の取得とフォーマット
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const formattedDate = `${year}/${month}/${day}`;

// DMMアフィリエイト検索URLのベース
const affiliateSearchUrlBase = 'https://affiliate.dmm.com/search_link?site=dmm&affiliateId=cycreator-003&service=mono&floor=dvd&sort=date&keyword=';

// APIのレスポンス（JSON）から動画リスト部分を抽出
// あなたのデータ構造に合わせて 'data.searchVideos.edges' の部分を調整する可能性があります
const videoEdges = items[0].json.data.searchVideos.edges;

// 最終的に出力する整形済みデータの配列
const formattedData = [];

// 各動画データをループ処理して情報を抽出
for (const [index, edge] of videoEdges.entries()) {
  const node = edge.node;

  // 順位（1から始まるように +1 する）
  const rank = index + 1;

  // タイトルと女優名の分割（元のJSロジックを再現）
  let title = node.titleName || '（タイトル不明）';
  let actress = '（女優名不明）';
  if (title !== '（タイトル不明）') {
    const parts = title.split(/\s+/);
    if (parts.length > 1) {
      actress = parts.pop();
      title = parts.join(' ');
    }
  }

  // サムネイルURLからスプレッドシート用関数を生成
  const thumbnailUrl = node.packageImage || '';
  const imageFormula = thumbnailUrl ? `=IMAGE("${thumbnailUrl}", 2)` : '';

  // 動画URLをIDから組み立てる (※APIレスポンスにURLがないため、一般的な形式から推測)
  const fullUrl = `https://tv.dmm.com/vod/detail/?season=${node.id}`;

  // 女優名からアフィリエイト検索URLを生成
  let affiliateSearchUrl = '';
  if (actress !== '（女優名不明）') {
    const encodedActress = encodeURIComponent(actress);
    affiliateSearchUrl = `${affiliateSearchUrlBase}${encodedActress}`;
  }

  // TSVの1行に相当するオブジェクトを作成
  const rowData = {
    '取得日': formattedDate,
    '検索カテゴリ': '23', // APIリクエストで指定したID。カテゴリ名はAPIレスポンスにないためIDを仮置き。
    'ジャンル': '', // ジャンル情報は現在のAPIレスポンスに含まれていないため空欄。
    'ソート順': 'RANK', // APIリクエストで指定したソート順
    '順位': rank,
    'サムネイル': imageFormula,
    'タイトル': title,
    '女優名': actress,
    'URL': fullUrl,
    '検索URL': affiliateSearchUrl
  };

  formattedData.push(rowData);
}

// n8nの次のノードへ、整形したデータを返す
return formattedData;

