// n8n Code Node - 最終修正版
// DMM Affiliate APIのレスポンスから「限定」商品を除外し、通常商品の情報を抽出します。
// さらに、前のノードから渡された「順位」「取得日」などの情報も引き継ぎます。

// 最終的な出力結果を格納する配列
const finalResults = [];

// n8nの入力アイテム (items) をインデックス付きで一つずつ処理します
for (const [index, inputItem] of items.entries()) {
  // 入力データにAPIレスポンスのitems配列が存在するか確認します
  if (inputItem.json && inputItem.json.result && Array.isArray(inputItem.json.result.items)) {
    const apiItems = inputItem.json.result.items;

    // 商品リストの中から「限定」や「チェキ付き」というキーワードを含まない通常商品を探します
    const normalItem = apiItems.find(item =>
      !item.title.includes('【数量限定】') && !item.title.includes('チェキ付き') && !item.title.includes('BOD')&& !item.title.includes('ブルーレイディスク')
    );

    // 通常商品が見つかった場合にのみ、処理を実行します
    if (normalItem) {
      // 女優名を抽出します (存在しない場合も考慮します)
      let actorName = '';
      if (normalItem.iteminfo && Array.isArray(normalItem.iteminfo.actor) && normalItem.iteminfo.actor.length > 0) {
        // 複数の女優がいる場合も考慮し、カンマ区切りで連結します
        actorName = normalItem.iteminfo.actor.map(a => a.name).join(', ');
      }

      // ご要望の「女優名＋タイトル名」での検索URLを生成します
      // タイトルから女優名（もし含まれていれば）を除外して、よりシンプルな検索キーワードにします
      const cleanTitle = normalItem.title.replace(`/${actorName}`, '').trim();
      const searchKeyword = actorName ? `${actorName} ${cleanTitle}` : cleanTitle;
      const encodedKeyword = encodeURIComponent(searchKeyword);
      const searchUrl = `https://affiliate.dmm.com/search_link?site=dmm&affiliateId=cycreator-003&service=mono&floor=dvd&sort=date&keyword=${encodedKeyword}`;

      // Googleスプレッドシートで見やすいように、サムネイル画像をIMAGE関数形式に変換します
      const thumbnailUrl = normalItem.imageURL?.large || normalItem.imageURL?.small || '';
      const thumbnailFormula = thumbnailUrl ? `=IMAGE("${thumbnailUrl}", 2)` : '';

      // 次のノードに渡すための出力データを作成します
      const outputData = {
        // ▼▼▼ ここから追加したフィールドです ▼▼▼
        順位: inputItem.json.順位 !== undefined ? inputItem.json.順位 : index + 1,
        取得日: inputItem.json.取得日 || new Date().toISOString().split("T")[0],
        検索カテゴリ: inputItem.json.検索カテゴリ || null,
        ソート順: inputItem.json.ソート順 || "NEW",
        // ▲▲▲ ここまで追加したフィールドです ▲▲▲

        // --- 以下は前回から引き継いだフィールドです ---
        サムネイル: thumbnailFormula,
        タイトル: normalItem.title,
        女優名: actorName,
        URL: normalItem.URL,
        検索URL: searchUrl, //← こちらが抽出したかったURLです
        アフィリエイトURL: normalItem.affiliateURL,
      };

      // 処理結果を最終出力配列に追加します
      finalResults.push({ json: outputData });
    }
    // 通常商品が見つからなかった場合は、何もせずスキップします
  }
}

// 整形した結果をn8nの次のノードに渡します
return finalResults;

// n8n Code Node - 修正版
// DMM Affiliate APIのレスポンスから「限定」商品を除外し、条件に合う通常商品の情報をすべて抽出します。
// また、前のノードから渡された「順位」「取得日」などの共通情報も各商品に引き継ぎます。

// 最終的な出力結果を格納する配列
const finalResults = [];

// n8nの入力アイテム (items) を一つずつ処理します
// itemsは前のノードからの出力の配列です
for (const [index, inputItem] of items.entries()) {
  // 入力データにAPIレスポンスの商品リスト(items)が存在するか確認します
  if (inputItem.json && inputItem.json.result && Array.isArray(inputItem.json.result.items)) {
    const apiItems = inputItem.json.result.items;

    // ▼▼▼【変更点1】find を filter に変更 ▼▼▼
    // 商品リストの中から「限定」や「チェキ付き」というキーワードを含まない通常商品を"すべて"抽出します
    const normalItems = apiItems.filter(item =>
      !item.title.includes('【数量限定】') && !item.title.includes('チェキ付き') && !item.title.includes('BOD')&& !item.title.includes('ブルーレイディスク')
    );

    // ▼▼▼【変更点2】抽出した全商品をループ処理 ▼▼▼
    // 抽出された通常商品が複数ある場合、それぞれを整形して結果に追加します
    for (const normalItem of normalItems) {
      // 女優名を抽出します (存在しない場合も考慮します)
      let actorName = '';
      if (normalItem.iteminfo && Array.isArray(normalItem.iteminfo.actor) && normalItem.iteminfo.actor.length > 0) {
        // 複数の女優がいる場合も考慮し、カンマ区切りで連結します
        actorName = normalItem.iteminfo.actor.map(a => a.name).join(', ');
      }

      // 女優名＋タイトル名での検索URLを生成します
      const cleanTitle = normalItem.title.replace(`/${actorName}`, '').trim();
      const searchKeyword = actorName ? `${actorName} ${cleanTitle}` : cleanTitle;
      const encodedKeyword = encodeURIComponent(searchKeyword);
      const searchUrl = `https://affiliate.dmm.com/search_link?site=dmm&affiliateId=cycreator-003&service=mono&floor=dvd&sort=date&keyword=${encodedKeyword}`;

      // サムネイル画像をIMAGE関数形式に変換します
      const thumbnailUrl = normalItem.imageURL?.large || normalItem.imageURL?.small || '';
      const thumbnailFormula = thumbnailUrl ? `=IMAGE("${thumbnailUrl}", 2)` : '';

      // 次のノードに渡すための出力データを作成します
      const outputData = {
        // 共通情報を前のノードから引き継ぎます
        順位: inputItem.json.順位 !== undefined ? inputItem.json.順位 : index + 1,
        取得日: inputItem.json.取得日 || new Date().toISOString().split("T")[0],
        検索カテゴリ: inputItem.json.検索カテゴリ || null,
        ソート順: inputItem.json.ソート順 || "NEW",

        // 各商品の個別情報
        サムネイル: thumbnailFormula,
        タイトル: normalItem.title,
        女優名: actorName,
        URL: normalItem.URL,
        検索URL: searchUrl,
        アフィリエイトURL: normalItem.affiliateURL,
      };

      // 処理結果を最終出力配列に追加します
      finalResults.push({ json: outputData });
    }
    // 該当する通常商品が見つからなかった場合は、このループは実行されず、何も出力されません
  }
}

// 整形したすべての結果をn8nの次のノードに渡します
return finalResults;
